changeSet.sql:
DROP TABLE IF EXISTS service_responsible_personnel_aud CASCADE;

CREATE TABLE service_responsible_personnel_aud (
    rev         integer  NOT NULL REFERENCES revinfo(rev),
    revend      integer,
    revtype     smallint,
    service_id  uuid     NOT NULL,
    employee_id uuid     NOT NULL,
    PRIMARY KEY (rev, service_id, employee_id)
);

CREATE INDEX IF NOT EXISTS idx_service_responsible_personnel_aud_rev
    ON service_responsible_personnel_aud (rev);

rollback.sql:
DROP TABLE IF EXISTS service_responsible_personnel_aud CASCADE;

CREATE TABLE service_responsible_personnel_aud (
    id          uuid     NOT NULL,
    rev         integer  NOT NULL REFERENCES revinfo(rev),
    revend      integer,
    revtype     smallint,
    service_id  uuid,
    employee_id uuid,
    PRIMARY KEY (id, rev)
);
